div.script:
document.addEventListener('DOMContentLoaded', function() {
const container = document.getElementById('student_profile_container');
const form = document.getElementById('student_profile_form');
const editBtn = document.getElementById('btnEditProfile');
const cancelBtn = document.getElementById('btnCancelEdit');
const actionButtons = document.getElementById('actionButtons');

// Store original form values
let originalFormData = new FormData(form);

function setMode(mode) {
const fields = form.querySelectorAll('.js-editable');
const editOnlyButtons = document.querySelectorAll('.js-edit-only');

if (mode === 'edit') {
// Enable editing
fields.forEach(el => el.removeAttribute('disabled'));
editOnlyButtons.forEach(el => el.classList.remove('d-none'));
actionButtons.classList.remove('d-none');
editBtn.classList.add('d-none');

// Store current values
originalFormData = new FormData(form);
} else {
// Disable editing
fields.forEach(el => el.setAttribute('disabled', 'disabled'));
editOnlyButtons.forEach(el => el.classList.add('d-none'));
actionButtons.classList.add('d-none');
editBtn.classList.remove('d-none');

// Restore original values on cancel
if (mode === 'cancel') {
fields.forEach(el => {
const name = el.getAttribute('name');
const originalValue = originalFormData.get(name);
if (originalValue !== null) {
if (el.type === 'checkbox') {
el.checked = originalValue === 'on';
} else {
el.value = originalValue;
}
}
});
}
}
}

// Event listeners
editBtn.addEventListener('click', function(e) {
e.preventDefault();
setMode('edit');
});

cancelBtn.addEventListener('click', function() {
setMode('cancel');
});

// Form submission validation
form.addEventListener('submit', function(e) {
const requiredFields = form.querySelectorAll('[required]:not([disabled])');
let isValid = true;

requiredFields.forEach(field => {
if (!field.value.trim()) {
isValid = false;
field.classList.add('is-invalid');
} else {
field.classList.remove('is-invalid');
}
});

if (!isValid) {
e.preventDefault();
alert('Please fill in all required fields');
}
});

// Initialize in view mode
setMode('view');

// Modal form handlers
const educationForm = document.getElementById('educationForm');
const parentForm = document.getElementById('parentForm');
const sponsorForm = document.getElementById('sponsorForm');

// Education form validation


// ── Education modal: toggle Group/GPA/Percentage vs Program/CGPA based on exam type ──
var SCHOOL_GPA_TYPES = ['ssc', 'hsc', 'dakhil', 'alim'];
var SCHOOL_PCT_TYPES = ['o_level', 'a_level'];
var SCHOOL_TYPES = SCHOOL_GPA_TYPES.concat(SCHOOL_PCT_TYPES);
var examTypeSelect = document.getElementById('modalExamType');

function toggleEducationFields() {
    var val = examTypeSelect.value;
    var isSchool = SCHOOL_TYPES.indexOf(val) !== -1;
    var isGpa = SCHOOL_GPA_TYPES.indexOf(val) !== -1;
    var isPct = SCHOOL_PCT_TYPES.indexOf(val) !== -1;

    // Show/hide field groups
    document.getElementById('fieldGroup').classList.toggle('d-none', !isSchool);
    document.getElementById('fieldProgram').classList.toggle('d-none', isSchool);
    document.getElementById('fieldGpa').classList.toggle('d-none', !isGpa);
    document.getElementById('fieldPercentage').classList.toggle('d-none', !isPct);
    document.getElementById('fieldCgpa').classList.toggle('d-none', isSchool);

    // Filter institution dropdown
    var instSelect = document.getElementById('modalInstitution');
    if (instSelect) {
        var targetFor = isSchool ? 'school_college' : 'university';
        Array.prototype.forEach.call(instSelect.options, function(opt) {
            if (!opt.value) return;
            var forAttr = opt.getAttribute('data-for');
            opt.hidden = forAttr && forAttr !== targetFor;
        });
        instSelect.value = '';
    }

    // Filter program dropdown (university-level only)
    var progSelect = document.getElementById('modalProgram');
    if (progSelect) {
        var targetType = (val === 'bachelor') ? 'undergraduate'
                    : (val === 'masters')  ? 'postgraduate'
                    : (val === 'diploma' || val === 'others') ? 'diploma'
                    : null;
        Array.prototype.forEach.call(progSelect.options, function(opt) {
            if (!opt.value) return;
            var typeAttr = opt.getAttribute('data-type');
            opt.hidden = targetType ? (typeAttr !== targetType) : false;
        });
        progSelect.value = '';
    }
}

if (examTypeSelect) {
    examTypeSelect.addEventListener('change', toggleEducationFields);
    toggleEducationFields();
}

// Parent form validation
if (parentForm) {
parentForm.addEventListener('submit', function(e) {
const name = parentForm.querySelector('[name="name"]');
const relation = parentForm.querySelector('[name="relation"]');

if (!name.value.trim()) {
e.preventDefault();
alert('Please enter parent name');
name.focus();
return false;
}
if (!relation.value) {
e.preventDefault();
alert('Please select relation');
relation.focus();
return false;
}
});
}

// Sponsor form validation
if (sponsorForm) {
sponsorForm.addEventListener('submit', function(e) {
const name = sponsorForm.querySelector('[name="name"]');
const relation = sponsorForm.querySelector('[name="relationship_id"]');

if (!name.value.trim()) {
e.preventDefault();
alert('Please enter sponsor name');
name.focus();
return false;
}
if (!relation.value) {
e.preventDefault();
alert('Please select relation');
relation.focus();
return false;
}
});
}

// Reset forms when modals are closed
const modals = ['addResultModal', 'addParentModal', 'addSponsorModal'];
modals.forEach(modalId => {
const modalEl = document.getElementById(modalId);
if (modalEl) {
modalEl.addEventListener('hidden.bs.modal', function() {
const form = this.querySelector('form');
if (form) {
form.reset();
// Remove validation classes
form.querySelectorAll('.is-invalid').forEach(el => {
el.classList.remove('is-invalid');
});
}
// Re-initialise education field visibility after reset
if (modalId === 'addResultModal' && examTypeSelect) {
    toggleEducationFields();
}
});
}
});

// Auto-dismiss alerts after 5 seconds
const alerts = document.querySelectorAll('.alert');
alerts.forEach(alert => {
setTimeout(() => {
alert.style.transition = 'opacity 0.3s ease';
alert.style.opacity = '0';
setTimeout(() => {
alert.remove();
}, 300);
}, 5000);
});
});
